+
+    #[test]
+    fn thread_info_new_no_parent() {
+        let info = ThreadInfo::new("tid-1", ThreadKind::Thread);
+        assert_eq!(info.thread_id, "tid-1");
+        assert!(info.parent_id.is_none());
+        assert_eq!(info.kind, ThreadKind::Thread);
+    }
