+    #[test]
+    fn thread_info_with_parent_id() {
+        let info = ThreadInfo::new("tid-2", ThreadKind::ForumTopic).with_parent_id("parent-99");
+        assert_eq!(info.parent_id, Some("parent-99".to_string()));
