+        let arr: Vec<i64> = canonical["arr"]
+            .as_array()
+            .unwrap()
+            .iter()
+            .map(|v| v.as_i64().unwrap())
+            .collect();
+        assert_eq!(arr, vec![3, 1, 2], "array element order must be preserved");
+    }
